#include <stdio.h>
#include <stdlib.h>

typedef struct Node{ long long val; struct Node* next; } Node;

Node* duplicateRemoval(Node* head){
    Node dummy; dummy.val=0; dummy.next=head;
    Node* prev=&dummy; Node* cur=head;
    while(cur){
        if(cur->next && cur->val==cur->next->val){
            long long dup=cur->val;
            while(cur && cur->val==dup){
                Node* tmp=cur; cur=cur->next; free(tmp);
            }
            prev->next=cur;
        }else{
            prev=cur; cur=cur->next;
        }
    }
    return dummy.next;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        Node* head=NULL; Node* tail=NULL;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld",&x);
            Node* node=(Node*)malloc(sizeof(Node));
            node->val=x; node->next=NULL;
            if(!head) head=node; else tail->next=node;
            tail=node;
        }
        head=duplicateRemoval(head);
        int first=1;
        for(Node* p=head;p;p=p->next){
            if(!first) printf(" ");
            printf("%lld",p->val);
            first=0;
        }
        printf("\n");
        while(head){ Node* tmp=head; head=head->next; free(tmp); }
    }
    return 0;
}

