#!/usr/bin/env python3
import sys

def duplicate_removal(head):
    dummy = [0, head]  # [val, next]
    prev = dummy
    cur = head
    while cur:
        if cur[1] and cur[0] == cur[1][0]:
            dup = cur[0]
            while cur and cur[0] == dup:
                cur = cur[1]
            prev[1] = cur
        else:
            prev = cur
            cur = cur[1]
    return dummy[1]

def build_linked(arr):
    head = None
    tail = None
    for v in arr:
        node = [v, None]
        if not head:
            head = node
        else:
            tail[1] = node
        tail = node
    return head

def to_list(head):
    res = []
    while head:
        res.append(str(head[0]))
        head = head[1]
    return res

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        head = build_linked(arr)
        head = duplicate_removal(head)
        out_lines.append(' '.join(to_list(head)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

