const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let output = [];
function buildList(arr){
  let head=null, tail=null;
  for(const v of arr){
    const node={val: Number(v), next: null};
    if(!head) head=node; else tail.next=node;
    tail=node;
  }
  return head;
}
function duplicateRemoval(head){
  const dummy={val:0, next:head};
  let prev=dummy, cur=head;
  while(cur){
    if(cur.next && cur.val===cur.next.val){
      const dup=cur.val;
      while(cur && cur.val===dup){
        cur=cur.next;
      }
      prev.next=cur;
    }else{
      prev=cur; cur=cur.next;
    }
  }
  return dummy.next;
}
for(let t=0;t<T;t++){
  const N = Number(input[idx++]);
  const arr = input.slice(idx, idx+N);
  idx+=N;
  let head = buildList(arr);
  head = duplicateRemoval(head);
  const vals=[];
  for(let p=head;p;p=p.next){ vals.push(p.val.toString()); }
  output.push(vals.join(' '));
}
